UPDATE flights SET mediaCount = 4 WHERE id = 180002;
UPDATE flights SET mediaCount = 3 WHERE id = 180003;

-- Verify final state
SELECT f.id, f.name, f.mediaCount, COUNT(m.id) as actual_media
FROM flights f
LEFT JOIN media m ON f.id = m.flightId
WHERE f.projectId = 1
GROUP BY f.id, f.name, f.mediaCount
ORDER BY f.id;

